'use client';
import { useState } from 'react';
import { doc, setDoc, addDoc, collection } from 'firebase/firestore';
import { db } from '@/lib/firebase';
import { useRouter } from 'next/navigation';
import { useAuth } from '@/context/AuthContext';
import { calculateScore } from '@/lib/scoreUtils';

// ── Generator ─────────────────────────────────────────────────────────────────

const FIRST_NAMES = ['Arjun', 'Priya', 'Rahul', 'Sneha', 'Karan', 'Aditi', 'Rohan', 'Neha', 'Vikram', 'Ananya', 'Siddharth', 'Meera', 'Kabir', 'Isha', 'Dev', 'Tara', 'Samir', 'Kavya', 'Aryan', 'Ria', 'Aarav', 'Nisha', 'Aman', 'Mitali'];
const LAST_NAMES = ['Mehta', 'Sharma', 'Kumar', 'Patel', 'Singh', 'Gupta', 'Verma', 'Reddy', 'Rao', 'Nair', 'Das', 'Bose', 'Chopra', 'Joshi', 'Kapoor'];
const COLLEGES = ['IIT Bombay', 'BITS Pilani', 'IIT Kharagpur', 'Manipal Institute of Technology', 'IIT Delhi', 'NIT Trichy', 'IIIT Hyderabad', 'VIT Vellore', 'SRM Chennai', 'Delhi Technological University'];
const ADJECTIVES = ['Swift', 'Neon', 'Marble', 'Cloud', 'Storm', 'Void', 'Dusk', 'Crimson', 'Azure', 'Silent', 'Iron', 'Plasma', 'Quantum', 'Solar', 'Lunar', 'Echo'];
const ANIMALS = ['Lynx', 'Moth', 'Fox', 'Tiger', 'Bear', 'Crane', 'Raven', 'Wolf', 'Owl', 'Hawk', 'Shark', 'Viper', 'Mantis', 'Panther', 'Falcon', 'Jackal'];
const TECH_POOL = ['Python', 'React', 'Node.js', 'Docker', 'Kubernetes', 'Go', 'Rust', 'C++', 'Java', 'Figma', 'Solidity', 'PyTorch', 'TensorFlow', 'SQL', 'MongoDB', 'AWS', 'GCP', 'Azure', 'GraphQL', 'Swift', 'Kotlin', 'Flutter'];
const NONTECH_POOL = ['Leadership', 'UI/UX Design', 'Product Management', 'Public Speaking', 'Technical Writing', 'Agile', 'Market Research', 'Mentoring', 'System Design', 'Storytelling'];
const DOMAIN_POOL = ['Healthcare', 'Farming', 'Travel', 'Food Tech', 'Education', 'Sustainability', 'FinTech', 'Safety', 'Web3', 'AI/ML', 'IoT', 'Cybersecurity'];
const PACES = ['hackathon', 'short-term', 'long-term'];

function randomChoice<T>(arr: T[]): T {
    return arr[Math.floor(Math.random() * arr.length)];
}

function randomSubset<T>(arr: T[], max: number): T[] {
    const shuffled = [...arr].sort(() => 0.5 - Math.random());
    return shuffled.slice(0, Math.floor(Math.random() * max) + 1);
}

function generateUsers(count: number) {
    const users = [];
    for (let i = 0; i < count; i++) {
        const fn = randomChoice(FIRST_NAMES);
        const ln = randomChoice(LAST_NAMES);
        const codeName = `${randomChoice(ADJECTIVES)} ${randomChoice(ANIMALS)}`;
        const base = {
            uid: `seed_user_gen_${i}`,
            codeName,
            email: `${fn.toLowerCase()}.${ln.toLowerCase()}@example.com`,
            phone: '',
            realName: `${fn} ${ln}`,
            college: randomChoice(COLLEGES),
            techSkills: randomSubset(TECH_POOL, 6),
            nonTechSkills: randomSubset(NONTECH_POOL, 3),
            aboutMe: `Passionate student builder. I love working on ${randomChoice(DOMAIN_POOL)} and experimenting with ${randomChoice(TECH_POOL)}. Always looking for the next big hackathon!`,
            hackathons: randomSubset(['Smart India Hackathon', 'ETHGlobal', 'HackMIT', 'MLH Hacks', 'TCS CodeVita'], 3),
            papers: Math.random() > 0.8 ? 1 : 0,
            patents: 0,
            cgpa: parseFloat((7 + Math.random() * 2.9).toFixed(1)), // 7.0 to 9.9
            competitions: [],
            certifications: randomSubset(['AWS Certified', 'Google Cloud Engineer', 'Meta Frontend Developer', 'DeepLearning.AI'], 2),
            internships: Math.random() > 0.5 ? ['Startup Intern'] : [],
            github: `${fn.toLowerCase()}${ln.toLowerCase()}`,
            linkedin: `${fn.toLowerCase()}${ln.toLowerCase()}`,
            codechef: Math.random() > 0.5 ? `${fn.toLowerCase()}_cc` : '',
            leetcode: Math.random() > 0.5 ? `${fn.toLowerCase()}_lc` : '',
            hackerrank: '',
            projects: [],
            collaborationCount: Math.floor(Math.random() * 10),
            rating: parseFloat((4 + Math.random() * 1).toFixed(1)), // 4.0 to 5.0
            reports: [],
            dateJoined: new Date().toISOString(),
            isActive: true,
            isStudent: true,
            profileCompleted: true,
            interviewCompleted: true,
            workingStyle: { pace: randomChoice(PACES), collaboration: 'mixed', leadership: 'either', risk: 'medium' },
            domains: randomSubset(DOMAIN_POOL, 2),
            availabilityHours: 10 + Math.floor(Math.random() * 20),
            keywords: [randomChoice(TECH_POOL).toLowerCase(), randomChoice(DOMAIN_POOL).toLowerCase()],
        };
        users.push({ ...base, score: calculateScore(base as any) });
    }
    return users;
}

const PROJECT_PREFIX = ['Smart', 'Decentralized', 'AI-powered', 'Hyper', 'Open', 'Secure', 'NextGen', 'Eco', 'Quantum', 'Campus'];
const PROJECT_NOUN = ['Health', 'Farm', 'Chain', 'Wallet', 'Learn', 'Track', 'Vision', 'Voice', 'Net', 'Sync', 'Bot', 'Hub'];

function generateProjects(count: number, users: any[]) {
    const projects = [];
    for (let i = 0; i < count; i++) {
        const owner = randomChoice(users);
        const domain = randomChoice(DOMAIN_POOL);
        projects.push({
            ownerId: owner.uid,
            ownerCodeName: owner.codeName,
            name: `${randomChoice(PROJECT_PREFIX)}${randomChoice(PROJECT_NOUN)}`,
            description: `A revolutionary project in the ${domain} space. We aim to disrupt the industry by combining ${randomChoice(TECH_POOL)} with ${randomChoice(TECH_POOL)}. Looking for passionate folks to join before our next launch.`,
            abstract: `Innovative platform for ${domain}.`,
            tags: randomSubset([...TECH_POOL, domain], 4),
            category: Math.random() > 0.8 ? 'hardware' : 'software',
            domain: domain.toLowerCase().replace('/', '-').replace(' ', '-'),
            isHackathon: Math.random() > 0.5,
            isCompetition: Math.random() > 0.8,
            interestedUsers: [],
            approvedUsers: [],
            teamSize: 2 + Math.floor(Math.random() * 4),
            createdAt: new Date().toISOString(),
            status: 'open',
            workingStylePace: randomChoice(PACES),
            commitmentHours: 5 + Math.floor(Math.random() * 20),
            desiredSkills: randomSubset(TECH_POOL, 3),
        });
    }
    return projects;
}

// ── Component ─────────────────────────────────────────────────────────────────
export default function SeedPage() {
    const { user } = useAuth();
    const router = useRouter();
    const [status, setStatus] = useState<string[]>([]);
    const [running, setRunning] = useState(false);
    const [done, setDone] = useState(false);

    const log = (msg: string) => setStatus(prev => [...prev, msg]);

    const runSeed = async () => {
        setRunning(true);
        setStatus([]);

        try {
            log('🧬 Generating 30 User Profiles...');
            const genUsers = generateUsers(30);

            log('🌱 Seeding Users into Firestore...');
            for (const u of genUsers) {
                await setDoc(doc(db, 'users', u.uid), u);
            }
            log(`✅ Inserted 30 users successfully.`);

            log('🧬 Generating 50 Projects...');
            const genProjects = generateProjects(50, genUsers);

            log('🚀 Seeding Projects into Firestore...');
            for (const p of genProjects) {
                await addDoc(collection(db, 'projects'), { ...p, id: undefined });
            }
            log(`✅ Inserted 50 projects successfully.`);

            log('🎉 Done! Database seeded with MASSIVE payload.');
            setDone(true);
        } catch (e: any) {
            log(`❌ Error: ${e?.message}`);
        } finally {
            setRunning(false);
        }
    };

    return (
        <div style={{
            minHeight: '100vh', background: 'var(--black)', fontFamily: 'var(--sans)',
            maxWidth: 430, margin: '0 auto', padding: '40px 24px',
        }}>
            <div style={{ marginBottom: 32 }}>
                <div style={{ fontSize: 28, color: 'var(--pure)', marginBottom: 4 }}>Massive Seed</div>
                <div style={{ fontSize: 12, color: 'var(--muted)', textTransform: 'uppercase', letterSpacing: 1 }}>
                    Admin · Large Data Generator
                </div>
            </div>

            <div style={{ background: 'var(--dark)', border: '1px solid var(--border)', borderRadius: 12, padding: 16, marginBottom: 24, fontSize: 13, color: 'var(--subtle)', lineHeight: 1.6 }}>
                This will proceduraly generate and insert <strong style={{ color: 'var(--white)' }}>30 User Profiles</strong> and <strong style={{ color: 'var(--white)' }}>50 Projects</strong> into Firestore.<br /><br />
                Use this to fully populate the app and test scrolling, filtering, and real-time syncing at scale.
            </div>

            {/* Removed "Please sign in first" warning */}

            <button
                onClick={runSeed}
                disabled={running || done}
                style={{
                    width: '100%', padding: '14px', marginBottom: 24,
                    background: done ? 'var(--mid)' : running ? 'var(--dark)' : 'var(--pure)',
                    color: done ? 'var(--subtle)' : 'var(--black)',
                    border: 'none', borderRadius: 12, fontSize: 14, fontWeight: 700,
                    fontFamily: 'var(--sans)', cursor: running || done ? 'not-allowed' : 'pointer',
                }}
            >
                {done ? 'Seeded ✓' : running ? 'Seeding...' : '🌱 Run Massive Seed'}
            </button>

            {status.length > 0 && (
                <div style={{ background: 'var(--dark)', border: '1px solid var(--border)', borderRadius: 12, padding: 16, fontSize: 12, color: 'var(--subtle)', lineHeight: 2, fontFamily: 'monospace' }}>
                    {status.map((s, i) => <div key={i}>{s}</div>)}
                </div>
            )}

            {done && (
                <div style={{ display: 'flex', gap: 10, marginTop: 20 }}>
                    <button onClick={() => router.push('/swipe')} style={{ flex: 1, padding: '12px', background: 'var(--pure)', color: 'var(--black)', border: 'none', borderRadius: 12, fontSize: 13, fontWeight: 700, fontFamily: 'var(--sans)', cursor: 'pointer' }}>
                        → Discover
                    </button>
                    <button onClick={() => router.push('/projects')} style={{ flex: 1, padding: '12px', background: 'var(--dark)', color: 'var(--white)', border: '1px solid var(--border)', borderRadius: 12, fontSize: 13, fontFamily: 'var(--sans)', cursor: 'pointer' }}>
                        → Projects
                    </button>
                </div>
            )}
        </div>
    );
}
